export async function GET() {
  try {
    console.log('--- EXPLICIT MASTER SEED START ---');
    
    // 1. Очистка
    await supabase.from('emojino_movies').delete().neq('id', '0');
    
    // 2. Вставка пачками по 50 записей (Supabase любит batch)
    const chunkSize = 50;
    for (let i = 0; i < finalData.length; i += chunkSize) {
      const chunk = finalData.slice(i, i + chunkSize);
      const { error } = await supabase.from('emojino_movies').insert(chunk);
      if (error) throw error;
      console.log(`Inserted chunk ${i / chunkSize + 1}`);
    }

    return NextResponse.json({ 
      success: true, 
      count: finalData.length,
      message: "Database updated with YOUR provided SQL list." 
    });

  } catch (error: any) {
    console.error('Seed error:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}
